using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;

namespace ConstExpr.Benchmarks.MathTests;

/// <summary>
/// Compares Math.Cbrt against the FastCbrt approximations generated by CbrtFunctionOptimizer,
/// and evaluates several faster scalar alternatives (no SIMD).
///
/// Two type groups are benchmarked:
///   Float  – MathF.Cbrt  vs Previous (2×Newton)  vs Current/HalleyOnly  vs NewtonHalley
///   Double – Math.Cbrt   vs Previous (2×Newton)  vs Current/NewtonHalley vs 3×Newton
///
/// Benchmark results on Apple M4 Pro (.NET 10, ARM64):
///   Float:  HalleyOnly  = 1.064 ns — 2.1× faster than MathF.Cbrt (2.28 ns)  ← NOW USED IN OPTIMIZER
///   Double: NewtonHalley = 2.199 ns — same cost as 2×Newton (~2.05 ns), but ~48-bit vs ~32-bit accuracy ← NOW USED
///
/// Run command:
///   dotnet run -c Release --project ConstExpr.Benchmarks/ConstExpr.Benchmarks.csproj --filter '*CbrtBenchmark*'
/// </summary>
[MemoryDiagnoser]
[GroupBenchmarksBy(BenchmarkLogicalGroupRule.ByCategory)]
[CategoriesColumn]
public class CbrtBenchmark
{
	private const int N = 1_024;
	private float[] _floatData = null!;
	private double[] _doubleData = null!;

	[GlobalSetup]
	public void Setup()
	{
		var rng = new Random(42);
		_floatData = new float[N];
		_doubleData = new double[N];

		for (var i = 0; i < N; i++)
		{
			// Mix of positive, negative, and near-zero values across many magnitudes.
			var exp = rng.NextDouble() * 20.0 - 10.0; // exponent range 1e-10 … 1e10
			var sign = rng.Next(2) == 0 ? 1.0 : -1.0;
			var v = sign * Math.Pow(10.0, exp);
			_floatData[i] = (float)v;
			_doubleData[i] = v;
		}
	}

	// ── float ──────────────────────────────────────────────────────────────

	/// <summary>Built-in MathF.Cbrt — hardware-accurate single-precision cube root.</summary>
	[Benchmark(Baseline = true, OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float DotNet_Float()
	{
		var sum = 0f;
		foreach (var v in _floatData)
			sum += MathF.Cbrt(v);
		return sum;
	}

	/// <summary>
	/// Previous FastCbrt(float): bit-hack + 2× Newton steps.
	/// Cost: 2 divisions, ~10 ops.  Accuracy: ~20 mantissa bits.
	/// Replaced by HalleyOnly in the optimizer.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float Previous_Float()
	{
		var sum = 0f;
		foreach (var v in _floatData)
			sum += PreviousFastCbrtFloat(v);
		return sum;
	}

	/// <summary>
	/// Current FastCbrt(float) — new optimizer output.
	/// Bit-hack + 1 Halley: y = y · (y³ + 2a) / (2y³ + a).
	/// Cost: 1 division, ~8 ops.  Accuracy: ~21 mantissa bits.
	/// Benchmarked at ~2.1× faster than MathF.Cbrt on ARM64.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float Current_Float()
	{
		var sum = 0f;
		foreach (var v in _floatData)
			sum += CurrentFastCbrtFloat(v);
		return sum;
	}

	/// <summary>
	/// FastCbrt(float) Newton+Halley: bit-hack + 1 Newton + 1 Halley.
	/// Cost: 2 divisions, ~12 ops.  Accuracy: ~30 mantissa bits.
	/// More accurate than Current but slower.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float NewtonHalley_Float()
	{
		var sum = 0f;
		foreach (var v in _floatData)
			sum += NewtonHalleyFastCbrtFloat(v);
		return sum;
	}

	// ── double ─────────────────────────────────────────────────────────────

	/// <summary>Built-in Math.Cbrt — hardware-accurate double-precision cube root.</summary>
	[Benchmark(Baseline = true, OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double DotNet_Double()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += Math.Cbrt(v);
		return sum;
	}

	/// <summary>
	/// Previous FastCbrt(double): bit-hack + 2× Newton steps.
	/// Cost: 2 divisions.  Accuracy: ~32 mantissa bits (double needs 53).
	/// Replaced by Newton+Halley in the optimizer.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double Previous_Double()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += PreviousFastCbrtDouble(v);
		return sum;
	}

	/// <summary>
	/// Current FastCbrt(double) — new optimizer output.
	/// Bit-hack + 1 Newton + 1 Halley.
	/// Cost: 2 divisions.  Accuracy: ~48 mantissa bits (vs ~32 for 2×Newton).
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double Current_Double()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += CurrentFastCbrtDouble(v);
		return sum;
	}

	/// <summary>
	/// FastCbrtV3(double): bit-hack + 3× Newton — full 53-bit double precision.
	/// Cost: 3 divisions.  Accuracy: ~64 mantissa bits (overkill but correct).
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double ThreeNewton_Double()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += ThreeNewtonFastCbrtDouble(v);
		return sum;
	}

	// ── previous implementations (old CbrtFunctionOptimizer — 2× Newton) ──

	private static float PreviousFastCbrtFloat(float x)
	{
		if (x == 0.0f)
			return 0.0f;

		var absX = Single.Abs(x);

		var i = BitConverter.SingleToInt32Bits(absX);
		i = 0x2a517d47 + i / 3;
		var y = BitConverter.Int32BitsToSingle(i);

		// 2× Newton: y = (2y + a/y²) / 3
		y = (y + y + absX / (y * y)) / 3.0f;
		y = (y + y + absX / (y * y)) / 3.0f;

		return Single.CopySign(y, x);
	}

	private static double PreviousFastCbrtDouble(double x)
	{
		if (x == 0.0)
			return 0.0;

		var absX = Double.Abs(x);

		var i = BitConverter.DoubleToInt64Bits(absX);
		i = 0x2a9f8b7cef1d0da0L + i / 3;
		var y = BitConverter.Int64BitsToDouble(i);

		// 2× Newton: y = (2y + a/y²) / 3
		y = (y + y + absX / (y * y)) / 3.0;
		y = (y + y + absX / (y * y)) / 3.0;

		return Double.CopySign(y, x);
	}

	// ── current implementations (new CbrtFunctionOptimizer — Halley-based) ──

	/// <summary>New float: 1 Halley only — 1 division, ~21-bit accuracy, ~2× faster than MathF.Cbrt.</summary>
	private static float CurrentFastCbrtFloat(float x)
	{
		if (x == 0.0f)
			return 0.0f;

		var absX = Single.Abs(x);

		var i = BitConverter.SingleToInt32Bits(absX);
		i = 0x2a517d47 + i / 3;
		var y = BitConverter.Int32BitsToSingle(i);

		// 1× Halley: y ← y · (y³ + 2a) / (2y³ + a)
		var y2 = y * y;
		var y3 = y2 * y;
		var twoA = absX + absX;
		y = y * Single.FusedMultiplyAdd(1.0f, y3, twoA) / Single.FusedMultiplyAdd(2.0f, y3, absX);

		return Single.CopySign(y, x);
	}

	/// <summary>New double: 1 Newton + 1 Halley — 2 divisions, ~48-bit accuracy.</summary>
	private static double CurrentFastCbrtDouble(double x)
	{
		if (x == 0.0)
			return 0.0;

		var absX = Double.Abs(x);

		var i = BitConverter.DoubleToInt64Bits(absX);
		i = 0x2a9f8b7cef1d0da0L + i / 3;
		var y = BitConverter.Int64BitsToDouble(i);

		// 1× Newton
		y = (y + y + absX / (y * y)) / 3.0;

		// 1× Halley: y ← y · (y³ + 2a) / (2y³ + a)
		var y2 = y * y;
		var y3 = y2 * y;
		var twoA = absX + absX;
		y = y * Double.FusedMultiplyAdd(1.0, y3, twoA) / Double.FusedMultiplyAdd(2.0, y3, absX);

		return Double.CopySign(y, x);
	}

	// ── additional alternatives ─────────────────────────────────────────────

	/// <summary>
	/// Float: 1 Newton + 1 Halley — 2 divisions, ~30-bit accuracy.
	/// More accurate than Current (1 Halley) but slower.
	/// </summary>
	private static float NewtonHalleyFastCbrtFloat(float x)
	{
		if (x == 0.0f)
			return 0.0f;

		var absX = Single.Abs(x);

		var i = BitConverter.SingleToInt32Bits(absX);
		i = 0x2a517d47 + i / 3;
		var y = BitConverter.Int32BitsToSingle(i);

		// 1× Newton
		y = (y + y + absX / (y * y)) / 3.0f;

		// 1× Halley
		var y2 = y * y;
		var y3 = y2 * y;
		var twoA = absX + absX;
		y = y * Single.FusedMultiplyAdd(1.0f, y3, twoA) / Single.FusedMultiplyAdd(2.0f, y3, absX);

		return Single.CopySign(y, x);
	}

	/// <summary>
	/// Double: 3× Newton — full 53-bit double precision.
	/// Cost: 3 divisions.
	/// </summary>
	private static double ThreeNewtonFastCbrtDouble(double x)
	{
		if (x == 0.0)
			return 0.0;

		var absX = Double.Abs(x);

		var i = BitConverter.DoubleToInt64Bits(absX);
		i = 0x2a9f8b7cef1d0da0L + i / 3;
		var y = BitConverter.Int64BitsToDouble(i);

		y = (y + y + absX / (y * y)) / 3.0;
		y = (y + y + absX / (y * y)) / 3.0;
		y = (y + y + absX / (y * y)) / 3.0;

		return Double.CopySign(y, x);
	}
}






